class ProductCell: UICollectionViewCell {
    private let nameLabel = UILabel()
    private let priceLabel = UILabel()
    private let imageView = UIImageView()

    override init(frame: CGRect) {
        super.init(frame: frame)
        setupUI()
    }

    private func setupUI() {
        [imageView, nameLabel, priceLabel].forEach { contentView.addSubview($0); $0.translatesAutoresizingMaskIntoConstraints = false }
        NSLayoutConstraint.activate([
            imageView.topAnchor.constraint(equalTo: contentView.topAnchor),
            imageView.leadingAnchor.constraint(equalTo: contentView.leadingAnchor),
            imageView.trailingAnchor.constraint(equalTo: contentView.trailingAnchor),
            imageView.heightAnchor.constraint(equalTo: imageView.widthAnchor),
        ])
    }
}

protocol ProductRepositoryProtocol {
    func getProducts() async throws -> [Product]
}

class MockProductRepository: ProductRepositoryProtocol {
    var productsToReturn: [Product] = []
    var errorToThrow: Error?

    func getProducts() async throws -> [Product] {
        if let error = errorToThrow { throw error }
        return productsToReturn
    }
}

class ProductViewModelTests: XCTestCase {
    func test_loadProducts_success() async {
        let mock = MockProductRepository()
        mock.productsToReturn = [Product(name: 'Test')]
        let vm = ProductViewModel(repository: mock)
        await vm.loadProducts()
        XCTAssertEqual(vm.products.count, 1)
    }
}

